namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string OfficeLocation { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public int InstructorId { get; set; }
    public bool IsFeatured { get; set; }
    public int MaxEnrollment { get; set; }
    public string Semester { get; set; } = string.Empty;
    public string Level { get; set; } = string.Empty; // Undergraduate, Graduate
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CourseCatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and rhetoric." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and fundamental forces." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and civilizations." },
            new() { Id = 6, Code = "BIO", Name = "Biology", Description = "Study of living organisms and life processes." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Ada Lovelace", Title = "Professor", Bio = "Expert in algorithms and computational theory with over 15 years of teaching experience. Research focuses on programming language design and formal methods.", Email = "alovelace@university.edu", OfficeLocation = "Science Hall 301" },
            new() { Id = 2, Name = "Dr. Alan Turing", Title = "Associate Professor", Bio = "Specializes in artificial intelligence and computability theory. Published extensively on machine learning and cognitive computing.", Email = "aturing@university.edu", OfficeLocation = "Science Hall 204" },
            new() { Id = 3, Name = "Dr. Emmy Noether", Title = "Professor", Bio = "Renowned mathematician focusing on abstract algebra and theoretical physics. Awarded the departmental excellence in teaching award three years running.", Email = "enoether@university.edu", OfficeLocation = "Math Building 105" },
            new() { Id = 4, Name = "Dr. Mary Shelley", Title = "Associate Professor", Bio = "Specializes in Romantic literature and creative writing. Author of several critically acclaimed novels and short story collections.", Email = "mshelley@university.edu", OfficeLocation = "Humanities 412" },
            new() { Id = 5, Name = "Dr. Richard Feynman", Title = "Professor", Bio = "Theoretical physicist known for making complex concepts accessible. Research interests include quantum electrodynamics and particle physics.", Email = "rfeynman@university.edu", OfficeLocation = "Physics Building 210" },
            new() { Id = 6, Name = "Dr. Mary Beard", Title = "Professor", Bio = "Classical historian specializing in ancient Rome. Award-winning author and public intellectual with a focus on making history engaging for all audiences.", Email = "mbeard@university.edu", OfficeLocation = "Humanities 308" },
            new() { Id = 7, Name = "Dr. Rosalind Franklin", Title = "Associate Professor", Bio = "Biophysicist and molecular biologist. Research focuses on the structure of DNA and RNA, with extensive lab experience in X-ray crystallography.", Email = "rfranklin@university.edu", OfficeLocation = "Life Sciences 115" },
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "Foundational course covering computational thinking, basic programming in Python, data types, control structures, and problem-solving strategies. No prior programming experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 101", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 120, Semester = "Fall 2026", Level = "Undergraduate" },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms). Includes analysis of time and space complexity.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Science Hall 203", DepartmentId = 1, InstructorId = 1, IsFeatured = false, MaxEnrollment = 60, Semester = "Fall 2026", Level = "Undergraduate" },
            new() { Id = 3, Code = "CS 310", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search algorithms, knowledge representation, machine learning fundamentals, natural language processing, and ethical considerations in AI deployment.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Location = "Science Hall 305", DepartmentId = 1, InstructorId = 2, IsFeatured = true, MaxEnrollment = 45, Semester = "Fall 2026", Level = "Undergraduate" },
            new() { Id = 4, Code = "CS 450", Title = "Software Engineering", Description = "Principles of software development including requirements analysis, system design, testing strategies, version control, agile methodologies, and team collaboration on a semester-long group project.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Science Hall 102", DepartmentId = 1, InstructorId = 2, IsFeatured = false, MaxEnrollment = 40, Semester = "Fall 2026", Level = "Undergraduate" },

            // Mathematics
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Introduction to differential calculus covering limits, continuity, derivatives, and their applications. Includes related rates, optimization problems, and an introduction to integration.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Building 201", DepartmentId = 2, InstructorId = 3, IsFeatured = true, MaxEnrollment = 90, Semester = "Fall 2026", Level = "Undergraduate" },
            new() { Id = 6, Code = "MATH 301", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues and eigenvectors. Applications to systems of equations, least squares, and geometric transformations.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Location = "Math Building 105", DepartmentId = 2, InstructorId = 3, IsFeatured = false, MaxEnrollment = 50, Semester = "Fall 2026", Level = "Undergraduate" },

            // English
            new() { Id = 7, Code = "ENG 110", Title = "College Writing", Description = "Develop critical reading, analytical thinking, and persuasive writing skills through essays, peer review, and revision workshops. Emphasis on clarity, argumentation, and research-based writing.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Humanities 201", DepartmentId = 3, InstructorId = 4, IsFeatured = false, MaxEnrollment = 25, Semester = "Fall 2026", Level = "Undergraduate" },
            new() { Id = 8, Code = "ENG 250", Title = "British Romantic Literature", Description = "Exploration of the Romantic period in British literature, covering poetry and prose by Blake, Wordsworth, Coleridge, Byron, Shelley, and Keats. Themes include nature, imagination, revolution, and the sublime.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", Location = "Humanities 412", DepartmentId = 3, InstructorId = 4, IsFeatured = true, MaxEnrollment = 30, Semester = "Fall 2026", Level = "Undergraduate" },

            // Physics
            new() { Id = 9, Code = "PHYS 101", Title = "General Physics I", Description = "Introductory mechanics covering kinematics, Newton's laws, work and energy, momentum, rotational motion, and gravitation. Includes weekly laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:50 PM", Location = "Physics Building 101", DepartmentId = 4, InstructorId = 5, IsFeatured = false, MaxEnrollment = 80, Semester = "Fall 2026", Level = "Undergraduate" },
            new() { Id = 10, Code = "PHYS 320", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave-particle duality, the Schrödinger equation, quantum states, operators, angular momentum, and the hydrogen atom. Mathematical prerequisites: linear algebra and differential equations.", Credits = 3, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Physics Building 210", DepartmentId = 4, InstructorId = 5, IsFeatured = true, MaxEnrollment = 35, Semester = "Fall 2026", Level = "Graduate" },

            // History
            new() { Id = 11, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, events, and themes from antiquity through the late medieval period, including Mesopotamia, Egypt, Greece, Rome, China, the Islamic world, and medieval Europe.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", Location = "Humanities 301", DepartmentId = 5, InstructorId = 6, IsFeatured = false, MaxEnrollment = 70, Semester = "Fall 2026", Level = "Undergraduate" },
            new() { Id = 12, Code = "HIST 340", Title = "The Roman Empire", Description = "In-depth study of Roman history from the founding of the Republic through the fall of the Western Empire. Topics include political institutions, military campaigns, daily life, art, and the transition to Christianity.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", Location = "Humanities 308", DepartmentId = 5, InstructorId = 6, IsFeatured = false, MaxEnrollment = 35, Semester = "Fall 2026", Level = "Undergraduate" },

            // Biology
            new() { Id = 13, Code = "BIO 101", Title = "Introduction to Biology", Description = "Survey of biological principles including cell structure, genetics, evolution, ecology, and organismal biology. Weekly laboratory sessions reinforce lecture concepts with hands-on experimentation.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM + Tue Lab 1:00–3:50 PM", Location = "Life Sciences 101", DepartmentId = 6, InstructorId = 7, IsFeatured = false, MaxEnrollment = 100, Semester = "Fall 2026", Level = "Undergraduate" },
            new() { Id = 14, Code = "BIO 310", Title = "Molecular Biology", Description = "Detailed study of molecular mechanisms of gene expression, DNA replication, transcription, translation, and regulation. Laboratory component includes modern techniques in molecular cloning and PCR.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM + Wed Lab 2:00–4:50 PM", Location = "Life Sciences 115", DepartmentId = 6, InstructorId = 7, IsFeatured = true, MaxEnrollment = 30, Semester = "Fall 2026", Level = "Undergraduate" },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public Department? GetDepartmentForCourse(int courseId)
    {
        var course = GetCourse(courseId);
        return course is null ? null : GetDepartment(course.DepartmentId);
    }

    public List<Course> SearchCourses(string? searchTerm, int? departmentId, string? level)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(level))
            query = query.Where(c => c.Level.Equals(level, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.Code).ToList();
    }

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

