@page "/"
@inject CourseCatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="mb-4">
    <h1>Welcome to the University Course Catalog</h1>
    <p class="lead">Browse our departments and courses for the Fall 2026 semester. Find the right courses for your academic path and submit your enrollment request online.</p>
</div>

<h2 class="mb-3">Featured Courses</h2>
<div class="row mb-5">
    @foreach (var course in featuredCourses)
    {
        var dept = CatalogService.GetDepartmentForCourse(course.Id);
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                    <div class="mb-2">
                        <span class="badge bg-primary">@course.Credits credits</span>
                        <span class="badge bg-secondary">@course.Level</span>
                        @if (dept is not null)
                        {
                            <span class="badge bg-info text-dark">@dept.Name</span>
                        }
                    </div>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                    <a href="enroll?courseId=@course.Id" class="btn btn-primary btn-sm">Enroll</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mb-3">Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        var courseCount = CatalogService.GetCoursesByDepartment(dept.Id).Count;
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <p class="text-muted mb-0">@courseCount course(s) available</p>
                </div>
                <div class="card-footer">
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

