@page "/courses"
@rendermode InteractiveServer
@inject CourseCatalogService CatalogService

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-4">
    <div class="col-md-4 mb-2">
        <input type="text" class="form-control" placeholder="Search courses..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-3 mb-2">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-3 mb-2">
        <select class="form-select" @bind="selectedLevel">
            <option value="">All Levels</option>
            <option value="Undergraduate">Undergraduate</option>
            <option value="Graduate">Graduate</option>
        </select>
    </div>
    <div class="col-md-2 mb-2">
        <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

<p class="text-muted">Showing @filteredCourses.Count course(s)</p>

@if (filteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria. Try adjusting your filters.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-hover">
            <thead class="table-light">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Level</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in filteredCourses)
                {
                    var dept = CatalogService.GetDepartmentForCourse(course.Id);
                    <tr>
                        <td><strong>@course.Code</strong></td>
                        <td>@course.Title</td>
                        <td>@dept?.Name</td>
                        <td>@course.Credits</td>
                        <td><span class="badge @(course.Level == "Graduate" ? "bg-warning text-dark" : "bg-secondary")">@course.Level</span></td>
                        <td><small>@course.Schedule</small></td>
                        <td>
                            <a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Department> departments = new();
    private List<Course> filteredCourses = new();

    private string _searchTerm = string.Empty;
    private int _selectedDepartmentId;
    private string _selectedLevel = string.Empty;

    private string searchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; ApplyFilters(); }
    }

    private int selectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; ApplyFilters(); }
    }

    private string selectedLevel
    {
        get => _selectedLevel;
        set { _selectedLevel = value; ApplyFilters(); }
    }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        if (DepartmentId.HasValue)
            _selectedDepartmentId = DepartmentId.Value;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        filteredCourses = CatalogService.SearchCourses(
            _searchTerm,
            _selectedDepartmentId > 0 ? _selectedDepartmentId : null,
            string.IsNullOrEmpty(_selectedLevel) ? null : _selectedLevel);
    }

    private void ClearFilters()
    {
        _searchTerm = string.Empty;
        _selectedDepartmentId = 0;
        _selectedLevel = string.Empty;
        ApplyFilters();
    }
}

@page "/courses/{Id:int}"
@inject CourseCatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            @if (department is not null)
            {
                <li class="breadcrumb-item"><a href="courses?departmentId=@department.Id">@department.Name</a></li>
            }
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@course.Code — @course.Title</h1>
            <div class="mb-3">
                <span class="badge bg-primary fs-6">@course.Credits credits</span>
                <span class="badge bg-secondary fs-6">@course.Level</span>
                <span class="badge bg-info text-dark fs-6">@course.Semester</span>
            </div>

            <h4>Description</h4>
            <p>@course.Description</p>

            <h4>Schedule & Location</h4>
            <table class="table table-bordered w-auto">
                <tr>
                    <th>Schedule</th>
                    <td>@course.Schedule</td>
                </tr>
                <tr>
                    <th>Location</th>
                    <td>@course.Location</td>
                </tr>
                <tr>
                    <th>Max Enrollment</th>
                    <td>@course.MaxEnrollment students</td>
                </tr>
            </table>

            <a href="enroll?courseId=@course.Id" class="btn btn-primary mt-2">Request Enrollment</a>
            <a href="courses" class="btn btn-outline-secondary mt-2 ms-2">Back to Courses</a>
        </div>

        <div class="col-lg-4">
            @if (instructor is not null)
            {
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Instructor</h5>
                        <h6 class="card-subtitle mb-2">@instructor.Name</h6>
                        <p class="text-muted mb-2">@instructor.Title</p>
                        <p class="card-text">@instructor.Bio</p>
                        <ul class="list-unstyled mb-0">
                            <li><strong>Email:</strong> @instructor.Email</li>
                            <li><strong>Office:</strong> @instructor.OfficeLocation</li>
                        </ul>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;
    private Department? department;
    private Instructor? instructor;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
        if (course is not null)
        {
            department = CatalogService.GetDepartment(course.DepartmentId);
            instructor = CatalogService.GetInstructor(course.InstructorId);
        }
    }
}

@page "/enroll"
@inject CourseCatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
        <strong>@selectedCourse?.Code — @selectedCourse?.Title</strong> has been received.
        You will be notified of your enrollment status via university email.</p>
    </div>
    <a href="courses" class="btn btn-primary">Browse More Courses</a>
    <a href="enroll" class="btn btn-outline-secondary ms-2">Submit Another Request</a>
}
else
{
    <p>Fill out the form below to request enrollment in a course. All fields are required.</p>

    <div class="row">
        <div class="col-lg-6">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId"
                               placeholder="e.g., S12345678" required />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId" required>
                        <option value="0" disabled>— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> courses = new();
    private Course? selectedCourse;
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Model.StudentName) ||
            string.IsNullOrWhiteSpace(Model.StudentId) ||
            Model.CourseId == 0)
            return;

        selectedCourse = CatalogService.GetCourse(Model.CourseId);
        CatalogService.SubmitEnrollment(Model);
        submitted = true;
    }
}

